{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select CT volume for processing",
      "simple": "Choose the CT scan of the shoulder from the volume list.",
      "detailed": "This CT will be used to analyze bone density and geometry for optimal screw placement. A good-quality scan ensures accurate segmentation and prosthesis planning. Select the appropriate CT volume from the dropdown."
    },
    {
      "step_id": "cb_step_2",
      "title": "Create bone segmentation",
      "simple": "Switch to the Segment Editor module and create a new segmentation named 'Bone_Segmentation'.",
      "detailed": "This segmentation will isolate the bone from surrounding tissues, enabling accurate measurement and prosthetic planning. In the Segment Editor, click 'Add' to create a new segmentation and name it 'Bone_Segmentation'."
    },
    {
      "step_id": "cb_step_3",
      "title": "Add bone segment",
      "simple": "Click the 'Add' button to create a new segment and rename it 'Bone_Segment'.",
      "detailed": "This segment will represent the bone region used for density optimization and 3D reconstruction. The segment name helps organize your work. Click 'Add', then rename the new segment to 'Bone_Segment'."
    },
    {
      "step_id": "cb_step_4",
      "title": "Open threshold tool",
      "simple": "Click the 'Threshold' button in the Segment Editor toolbar.",
      "detailed": "Thresholding converts CT Hounsfield units into a binary mask of bone tissue. Adjusting the range will determine which pixels are included as bone. Click 'Threshold' to open the thresholding options."
    },
    {
      "step_id": "cb_step_5",
      "title": "Set bone density threshold",
      "simple": "Adjust the threshold slider so that bone is highlighted and other tissues are excluded.",
      "detailed": "The threshold range separates bone from soft tissue based on density. Accurate thresholding ensures the reconstruction represents the true bone anatomy. Set the lower and upper bounds to match cortical and trabecular bone values typical for your patient."
    },
    {
      "step_id": "cb_step_6",
      "title": "Apply threshold",
      "simple": "Click the 'Apply' button to create the bone mask.",
      "detailed": "This applies the threshold to the current segment, creating a binary mask of bone. Review the result in the slice views before proceeding."
    },
    {
      "step_id": "cb_step_7",
      "title": "Open island removal tool",
      "simple": "Click the 'Islands' button in the Segment Editor.",
      "detailed": "The islands tool helps clean the segmentation by removing disconnected fragments that are not part of the main bone structure. This improves the quality of the 3D model."
    },
    {
      "step_id": "cb_step_8",
      "title": "Keep largest bone island",
      "simple": "Choose the 'Keep largest island' option from the dropdown.",
      "detailed": "This retains only the largest connected bone region, typically the glenoid and scapula, while discarding smaller artifacts or separate bone fragments. This ensures the reconstruction is focused on the relevant anatomy."
    },
    {
      "step_id": "cb_step_9",
      "title": "Apply island filter",
      "simple": "Click the 'Apply' button to keep only the largest island.",
      "detailed": "This finalizes the cleaned bone segmentation, removing any extraneous islands. Your bone mask should now accurately represent the glenoid and surrounding bone."
    },
    {
      "step_id": "cb_step_10",
      "title": "Select bone segment",
      "simple": "Choose the 'Bone_Segment' node from the segment list.",
      "detailed": "This identifies the segment that will be used for 3D reconstruction and screw planning. Selecting the correct segment ensures the subsequent steps use the right anatomy."
    },
    {
      "step_id": "cb_step_11",
      "title": "Generate 3D bone model",
      "simple": "Click the '3D Reconstruction' button to create a 3D surface model of the bone.",
      "detailed": "This converts the binary segmentation into a 3D surface that can be visualized and manipulated for planning. The model provides a realistic view of the glenoid anatomy for screw trajectory planning."
    },
    {
      "step_id": "cb_step_12",
      "title": "Adjust 3D view angle",
      "simple": "Rotate and zoom the 3D view to get a clear view of the glenoid cavity surface.",
      "detailed": "A good view of the glenoid is essential for accurately placing the prosthesis center point. Adjust the view so you can see the articular surface clearly."
    },
    {
      "step_id": "cb_step_13",
      "title": "Create fiducial point",
      "simple": "Switch to the Markups module and create a new point list named 'Prosthesis_center_point'.",
      "detailed": "This point will mark the planned center of the glenoid prosthesis on the bone surface. It serves as the reference for prosthesis alignment. Create a new MarkupsFiducial node and name it accordingly."
    },
    {
      "step_id": "cb_step_14",
      "title": "Place prosthesis center",
      "simple": "Click on the glenoid cavity surface in the 3D view to place the fiducial point at the desired prosthesis center.",
      "detailed": "Place the point exactly at the center of the glenoid articular surface. This defines the position of the prosthetic component and influences screw angulation. Confirm the placement by reviewing in multiple slice views."
    },
    {
      "step_id": "cb_step_15",
      "title": "Select prosthesis center fiducial",
      "simple": "Choose the 'Prosthesis_center_point' fiducial from the list.",
      "detailed": "This identifies the point you just placed as the input for prosthesis implantation. Selection ensures the extension uses the correct anatomical landmark."
    },
    {
      "step_id": "cb_step_16",
      "title": "Run prosthesis implantation",
      "simple": "Click the 'Prosthesis implantation' button to generate the initial prosthesis plan.",
      "detailed": "The extension uses the bone model and center point to optimally size and position a glenoid prosthesis, including screw trajectories. This is the core planning step."
    },
    {
      "step_id": "cb_step_17",
      "title": "Decide if prosthesis adjustment needed",
      "simple": "If you are satisfied with the prosthesis position, choose 'No, proceed to next step'. Otherwise, check 'Adjust prosthesis'.",
      "detailed": "The automatic placement may need fine-tuning. Selecting adjustment will activate transform handles to modify the prosthesis position. If it looks correct, you can skip to the Plan step."
    },
    {
      "step_id": "cb_step_18",
      "title": "Fine-tune prosthesis position",
      "simple": "Drag the 3D transform handles to reposition the prosthesis as needed.",
      "detailed": "Use the handles to translate or rotate the prosthesis for better alignment with the glenoid anatomy. This ensures optimal fit and screw placement."
    },
    {
      "step_id": "cb_step_19",
      "title": "Update prosthesis position",
      "simple": "Click the 'Update Prosthesis' button to apply your manual adjustments.",
      "detailed": "This confirms the new position and recalculates screw trajectories based on the adjusted prosthesis location."
    },
    {
      "step_id": "cb_step_20",
      "title": "Generate final screw plan",
      "simple": "Click the 'Plan' button to generate the screw trajectories.",
      "detailed": "The extension computes optimal screw paths based on the prosthesis position and bone density data. This produces the final surgical plan."
    },
    {
      "step_id": "cb_step_21",
      "title": "Decide if screw adjustment needed",
      "simple": "If the screw paths look correct, choose 'No, stop'. Otherwise, check 'Adjust screw' to modify endpoints.",
      "detailed": "The automatic screw planning may require fine-tuning of entry points or trajectories. If adjustment is needed, you can drag screw path endpoints. If satisfied, the plan is complete."
    },
    {
      "step_id": "cb_step_22",
      "title": "Fine-tune screw paths",
      "simple": "Drag the endpoints of each screw path to adjust the entry point and trajectory.",
      "detailed": "Modify the screw start and end points to avoid critical structures and achieve optimal bone purchase. Verify in the 3D view and axial slices."
    },
    {
      "step_id": "cb_step_23",
      "title": "Update screw plan",
      "simple": "Click the 'Update screw' button to save your adjustments.",
      "detailed": "This finalizes the screw trajectories. The plan is now ready for surgical reference."
    }
  ]
}
